<script type="text/babel">
const INK = '#0a0a0a';
const PAPER = '#f4f1ea';
const mono = `'JetBrains Mono', ui-monospace, 'Courier New', monospace`;
const display = `'Archivo Black', Impact, sans-serif`;

/* Sunburst — N rays emanating from a center, ending at the cell edge.
 * variant: 'lines' (1px hairlines), 'wedges' (alternating filled triangles),
 *          'tapered' (line widths fade with angle).
 * coreRatio: dot diameter relative to shorter side.
 */
function Sunburst({
  w, h, rays = 96, coreRatio = 0.18, variant = 'lines',
  bg = PAPER, ink = INK, dot = INK,
  innerRatio = null, // start radius for rays (relative to dot radius); null = touch dot
  outerScale = 1.4,  // how far past frame the rays extend (cropped)
  cx, cy,
}) {
  cx = cx ?? w / 2;
  cy = cy ?? h / 2;
  const short = Math.min(w, h);
  const coreR = (short * coreRatio) / 2;
  const startR = innerRatio != null ? coreR * innerRatio : coreR + 1;
  const outerR = Math.hypot(w, h) * outerScale * 0.5;

  const elements = [];
  if (variant === 'lines') {
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      const x1 = cx + Math.cos(a) * startR;
      const y1 = cy + Math.sin(a) * startR;
      const x2 = cx + Math.cos(a) * outerR;
      const y2 = cy + Math.sin(a) * outerR;
      elements.push(<line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke={ink} strokeWidth="1" />);
    }
  } else if (variant === 'wedges') {
    const step = (Math.PI * 2) / rays;
    for (let i = 0; i < rays; i += 2) {
      const a0 = i * step, a1 = (i + 1) * step;
      const p0x = cx + Math.cos(a0) * startR;
      const p0y = cy + Math.sin(a0) * startR;
      const p1x = cx + Math.cos(a1) * startR;
      const p1y = cy + Math.sin(a1) * startR;
      const p2x = cx + Math.cos(a1) * outerR;
      const p2y = cy + Math.sin(a1) * outerR;
      const p3x = cx + Math.cos(a0) * outerR;
      const p3y = cy + Math.sin(a0) * outerR;
      elements.push(
        <path key={i} d={`M ${p0x} ${p0y} L ${p1x} ${p1y} L ${p2x} ${p2y} L ${p3x} ${p3y} Z`} fill={ink} />
      );
    }
  } else if (variant === 'tapered') {
    // every other ray slightly thicker — gives a denser-sparser rhythm
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      const x1 = cx + Math.cos(a) * startR;
      const y1 = cy + Math.sin(a) * startR;
      const x2 = cx + Math.cos(a) * outerR;
      const y2 = cy + Math.sin(a) * outerR;
      const sw = i % 4 === 0 ? 1.5 : 1;
      elements.push(<line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke={ink} strokeWidth={sw} />);
    }
  }

  return (
    <div style={{
      width: w, height: h, background: bg, position: 'relative', overflow: 'hidden',
      boxShadow: '0 1px 3px rgba(0,0,0,0.10), 0 4px 16px rgba(0,0,0,0.06)',
      flexShrink: 0,
    }}>
      <svg width={w} height={h} style={{ position: 'absolute', inset: 0 }}>
        {elements}
        <circle cx={cx} cy={cy} r={coreR} fill={dot} />
      </svg>
    </div>
  );
}

/* Engineering plate frame wrapping a sunburst — the 05 + sunburst marriage */
function PlateBurst({ w, h, rays, variant = 'lines', coreRatio = 0.16, frameInset = 0.04, label, sub, bg = PAPER, ink = INK, dot = INK }) {
  const pad = Math.round(Math.min(w, h) * frameInset);
