            // Ray count must drop with size or it muds out at small.
            const rays = s >= 160 ? 144 : s >= 96 ? 96 : s >= 64 ? 60 : s >= 48 ? 40 : s >= 32 ? 28 : s >= 24 ? 20 : 16;
            const core = s >= 96 ? 0.20 : s >= 48 ? 0.26 : s >= 24 ? 0.34 : 0.45;
            return (
              <div key={s} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 10 }}>
                <Sunburst w={s} h={s} rays={rays} variant="lines" coreRatio={core} />
                <div style={{ fontFamily: mono, fontSize: 9, color: 'rgba(40,30,20,0.7)' }}>
                  {s}px · {rays}r
                </div>
              </div>
            );
          })}
        </div>
      </Row>

      <Row title="SCALE TEST · ROUND" sub="avatar mode">
        <div style={{ display: 'flex', gap: 24, alignItems: 'flex-end' }}>
          {[128, 96, 64, 48, 32, 24, 16].map(s => {
            const rays = s >= 96 ? 96 : s >= 64 ? 60 : s >= 48 ? 40 : s >= 32 ? 28 : s >= 24 ? 20 : 16;
            const core = s >= 96 ? 0.22 : s >= 48 ? 0.28 : s >= 24 ? 0.36 : 0.48;
            return (
              <div key={s} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 10 }}>
                <div style={{ width: s, height: s, borderRadius: '50%', overflow: 'hidden',
