                </div>
                <div style={{ fontFamily: mono, fontSize: 9, color: 'rgba(40,30,20,0.7)' }}>{s}px</div>
              </div>
            );
          })}
        </div>
      </Row>

      <div style={{ height: 60 }} />
    </DesignCanvas>
  );
}

ReactDOM.createRoot(document.getElementById('root')).render(<App />);
