// 10 logo concepts for Black Atom Industries
// All 400x400, black on paper, 1px strokes, squared corners.

const INK = '#0a0a0a';
const PAPER = '#f4f1ea';

const mono = `'JetBrains Mono', ui-monospace, 'Courier New', monospace`;
const display = `'Archivo Black', 'Helvetica Neue', Impact, sans-serif`;

// Shared frame for each logo cell
function Logo({ children, bg = PAPER }) {
  return (
    <div style={{
      width: 400, height: 400, background: bg, color: INK,
      position: 'relative', overflow: 'hidden',
      fontFamily: mono,
    }}>
      {children}
    </div>
  );
}

// Small uppercase mono corner labels for the datasheet feel
function CornerLabel({ top, left, right, bottom, children, size = 9 }) {
  return (
    <div style={{
      position: 'absolute', top, left, right, bottom,
      fontFamily: mono, fontSize: size, letterSpacing: '0.15em',
