/* Black Atom Industries — Mark Components (JSX)
 *
 * Three mark variants as React components. Import via:
 *   <script type="text/babel" src="assets/marks.jsx"></script>
 *
 * All components accept width/height and polarity props.
 * Requires React 18 in scope.
 */

const BAI_INK = '#0a0a0a';
const BAI_PAPER = '#f4f1ea';
const BAI_MONO = `'JetBrains Mono', ui-monospace, 'Courier New', monospace`;
const BAI_DISPLAY = `'Archivo Black', 'Helvetica Neue', Impact, sans-serif`;

/* ── SUNBURST ──────────────────────────────────────────────────
 * Primary mark. Dense radial hairlines from a solid core.
 * Props: w, h, rays (96), coreRatio (0.18), variant ('lines'|'wedges'|'tapered'),
 *        bg, ink, dot, cx, cy
 */
function BAI_Sunburst({
  w, h, rays = 96, coreRatio = 0.18, variant = 'lines',
  bg = 'transparent', ink = BAI_INK, dot = BAI_INK,
  cx: _cx, cy: _cy,
}) {
  const cx = _cx ?? w / 2, cy = _cy ?? h / 2;
  const short = Math.min(w, h);
  const coreR = (short * coreRatio) / 2;
  const startR = coreR + 1;
  const outerR = Math.hypot(w, h) * 0.7;

  const elements = [];
  if (variant === 'lines') {
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      elements.push(<line key={i}
        x1={cx + Math.cos(a) * startR} y1={cy + Math.sin(a) * startR}
        x2={cx + Math.cos(a) * outerR} y2={cy + Math.sin(a) * outerR}
        stroke={ink} strokeWidth="1" />);
    }
  } else if (variant === 'wedges') {
    const step = (Math.PI * 2) / rays;
    for (let i = 0; i < rays; i += 2) {
      const a0 = i * step, a1 = (i + 1) * step;
      elements.push(<path key={i} fill={ink} d={`
        M ${cx + Math.cos(a0) * startR} ${cy + Math.sin(a0) * startR}
        L ${cx + Math.cos(a1) * startR} ${cy + Math.sin(a1) * startR}
        L ${cx + Math.cos(a1) * outerR} ${cy + Math.sin(a1) * outerR}
        L ${cx + Math.cos(a0) * outerR} ${cy + Math.sin(a0) * outerR} Z`} />);
    }
  } else if (variant === 'tapered') {
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      elements.push(<line key={i}
        x1={cx + Math.cos(a) * startR} y1={cy + Math.sin(a) * startR}
        x2={cx + Math.cos(a) * outerR} y2={cy + Math.sin(a) * outerR}
        stroke={ink} strokeWidth={i % 4 === 0 ? 1.5 : 1} />);
    }
  }

  return (
    <svg width={w} height={h} style={{ display: 'block', background: bg, overflow: 'hidden' }}>
      {elements}
      <circle cx={cx} cy={cy} r={coreR} fill={dot} />
    </svg>
  );
}

/* ── FRAME + DOT (Mark 05) ─────────────────────────────────────
 * Functional mark. 1px square frame, centered dot, SVG geometry.
 * Props: w, h, frameInset (0.12), dotRatio (0.09), round, bg, stroke, fill
 */
function BAI_FrameDot({
  w, h, frameInset = 0.12, dotRatio = 0.09,
  round = false, bg = 'transparent', stroke = BAI_INK, fill = BAI_INK,
}) {
  const short = Math.min(w, h);
  const pad = Math.max(2, Math.round(short * frameInset));
  const fw = w - pad * 2, fh = h - pad * 2;
  const dotD = Math.max(2, Math.round(Math.min(fw, fh) * dotRatio));
  return (
    <svg width={w} height={h} shapeRendering="crispEdges"
      style={{ display: 'block', background: bg, borderRadius: round ? '50%' : 0 }}>
      <rect x={pad + 0.5} y={pad + 0.5} width={fw - 1} height={fh - 1}
        fill="none" stroke={stroke} strokeWidth="1" />
      <circle cx={w / 2} cy={h / 2} r={dotD / 2} fill={fill} shapeRendering="auto" />
    </svg>
  );
}

/* ── PLATE-BURST ───────────────────────────────────────────────
 * Hybrid. Sunburst inside an engineering frame.
 * Props: w, h, rays, variant, coreRatio, frameInset, label, sub, bg, ink, dot
 */
function BAI_PlateBurst({
  w, h, rays = 96, variant = 'lines', coreRatio = 0.16,
  frameInset = 0.04, label, sub, bg = BAI_PAPER, ink = BAI_INK, dot = BAI_INK,
}) {
  const pad = Math.round(Math.min(w, h) * frameInset);
  return (
    <div style={{
      width: w, height: h, background: bg, position: 'relative', overflow: 'hidden',
      flexShrink: 0,
    }}>
      <svg width={w} height={h} shapeRendering="crispEdges"
        style={{ position: 'absolute', inset: 0, zIndex: 2 }}>
        <rect x={pad + 0.5} y={pad + 0.5} width={w - pad * 2 - 1} height={h - pad * 2 - 1}
          fill="none" stroke={ink} strokeWidth="1" />
      </svg>
      <div style={{ position: 'absolute', inset: pad + 1, overflow: 'hidden' }}>
        <BAI_Sunburst w={w - pad * 2 - 2} h={h - pad * 2 - 2}
          rays={rays} variant={variant} coreRatio={coreRatio} bg={bg} ink={ink} dot={dot} />
      </div>
      {label && <div style={{
        position: 'absolute', top: pad + 10, left: pad + 12, zIndex: 3,
        fontFamily: BAI_MONO, fontSize: 9, letterSpacing: '0.25em',
        textTransform: 'uppercase', color: ink, background: bg, padding: '0 6px',
      }}>{label}</div>}
      {sub && <div style={{
        position: 'absolute', bottom: pad + 10, right: pad + 12, zIndex: 3,
        fontFamily: BAI_MONO, fontSize: 9, letterSpacing: '0.25em',
        textTransform: 'uppercase', color: ink, background: bg, padding: '0 6px',
      }}>{sub}</div>}
    </div>
  );
}

/* ── WORDMARK LOCKUP ───────────────────────────────────────────
 * Sunburst + "BLACK ATOM" + "INDUSTRIES"
 * Props: size ('sm'|'md'|'lg'|'xl'), color, stacked, rays
 */
function BAI_Wordmark({ size = 'md', color = BAI_INK, stacked = false, rays = 96 }) {
  const cfg = {
    sm: { mark: 48,  title: 16, sub: 8,  gap: 12 },
    md: { mark: 120, title: 36, sub: 11, gap: 24 },
    lg: { mark: 180, title: 56, sub: 14, gap: 36 },
    xl: { mark: 260, title: 88, sub: 16, gap: 48 },
  }[size];
  const mark = <BAI_Sunburst w={cfg.mark} h={cfg.mark} rays={rays} ink={color} dot={color} />;
  if (stacked) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: cfg.gap, color }}>
        {mark}
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontFamily: BAI_DISPLAY, fontSize: cfg.title, letterSpacing: '-0.01em', lineHeight: 0.92 }}>
            BLACK ATOM
          </div>
          <div style={{ fontFamily: BAI_MONO, fontSize: cfg.sub, letterSpacing: '0.55em', paddingLeft: '0.55em', marginTop: cfg.gap * 0.4 }}>
            INDUSTRIES
          </div>
        </div>
      </div>
    );
  }
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: cfg.gap, color }}>
      {mark}
      <div>
        <div style={{ fontFamily: BAI_DISPLAY, fontSize: cfg.title, letterSpacing: '-0.01em', lineHeight: 0.92 }}>
          BLACK ATOM
        </div>
        <div style={{ fontFamily: BAI_MONO, fontSize: cfg.sub, letterSpacing: '0.55em', paddingLeft: '0.55em', marginTop: cfg.gap * 0.4 }}>
          INDUSTRIES
        </div>
      </div>
    </div>
  );
}

Object.assign(window, {
  BAI_Sunburst, BAI_FrameDot, BAI_PlateBurst, BAI_Wordmark,
  BAI_INK, BAI_PAPER, BAI_MONO, BAI_DISPLAY,
});

