#!/usr/bin/env node
/**
 * Generate standalone SVG files from the Sunburst Study React components.
 *
 * Replicates the exact geometry math from the Sunburst, PlateBurst components
 * so the SVGs match what the React code produces at runtime.
 */

import { writeFileSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT = join(__dirname, 'assets', 'study-extracted');

// ── Tokens ──────────────────────────────────────────────────────────────
const INK = '#0a0a0a';
const PAPER = '#f4f1ea';

// ── Geometry helpers ─────────────────────────────────────────────────────
function sunburstElements({ w, h, rays = 96, coreRatio = 0.18, variant = 'lines', cx, cy, ink = INK }) {
  cx = cx ?? w / 2;
  cy = cy ?? h / 2;
  const short = Math.min(w, h);
  const coreR = (short * coreRatio) / 2;
  const startR = coreR + 1;
  const outerR = Math.hypot(w, h) * 0.7;

  const lines = [];
  if (variant === 'lines') {
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      const x1 = (cx + Math.cos(a) * startR).toFixed(2);
      const y1 = (cy + Math.sin(a) * startR).toFixed(2);
      const x2 = (cx + Math.cos(a) * outerR).toFixed(2);
      const y2 = (cy + Math.sin(a) * outerR).toFixed(2);
      lines.push(`      <line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${ink}" stroke-width="1"/>`);
    }
  } else if (variant === 'wedges') {
    const step = (Math.PI * 2) / rays;
    for (let i = 0; i < rays; i += 2) {
      const a0 = i * step, a1 = (i + 1) * step;
      const coords = [
        (cx + Math.cos(a0) * startR).toFixed(2), (cy + Math.sin(a0) * startR).toFixed(2),
        (cx + Math.cos(a1) * startR).toFixed(2), (cy + Math.sin(a1) * startR).toFixed(2),
        (cx + Math.cos(a1) * outerR).toFixed(2), (cy + Math.sin(a1) * outerR).toFixed(2),
        (cx + Math.cos(a0) * outerR).toFixed(2), (cy + Math.sin(a0) * outerR).toFixed(2),
      ];
      lines.push(`      <path d="M ${coords[0]} ${coords[1]} L ${coords[2]} ${coords[3]} L ${coords[4]} ${coords[5]} L ${coords[6]} ${coords[7]} Z" fill="${ink}"/>`);
    }
  } else if (variant === 'tapered') {
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      const x1 = (cx + Math.cos(a) * startR).toFixed(2);
      const y1 = (cy + Math.sin(a) * startR).toFixed(2);
      const x2 = (cx + Math.cos(a) * outerR).toFixed(2);
      const y2 = (cy + Math.sin(a) * outerR).toFixed(2);
      const sw = i % 4 === 0 ? '1.5' : '1';
      lines.push(`      <line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${ink}" stroke-width="${sw}"/>`);
    }
  }
  return { lines, coreR };
}

function makeSunburstSVG({ w, h, rays, coreRatio, variant, bg = 'transparent', ink = INK, dot = INK, label = 'sunburst' }) {
  const { lines, coreR } = sunburstElements({ w, h, rays, coreRatio, variant, ink });
  const cx = (w / 2).toFixed(2);
  const cy = (h / 2).toFixed(2);
  const sr = (coreR).toFixed(2);
  return {
    svg: `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${w}" height="${h}">
  <rect width="${w}" height="${h}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx}" cy="${cy}" r="${sr}" fill="${dot}"/>
</svg>`,
    label
  };
}

function makePlateBurstSVG({ w, h, rays = 96, variant = 'lines', coreRatio = 0.16, frameInset = 0.04, bg = PAPER, ink = INK, dot = INK, label = 'plate-burst' }) {
  const pad = Math.round(Math.min(w, h) * frameInset);
  const innerW = w - pad * 2 - 2;
  const innerH = h - pad * 2 - 2;
  const { lines: burstLines, coreR } = sunburstElements({ w: innerW, h: innerH, rays, coreRatio, variant, cx: innerW / 2, cy: innerH / 2, ink });
  const burstCX = (innerW / 2).toFixed(2);
  const burstCY = (innerH / 2).toFixed(2);
  const sr = (coreR).toFixed(2);
  return {
    svg: `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${w}" height="${h}">
  <rect width="${w}" height="${h}" fill="${bg}"/>
  <g>
    <clipPath id="burst-clip">
      <rect x="${pad + 1}" y="${pad + 1}" width="${innerW}" height="${innerH}"/>
    </clipPath>
  </g>
  <g clip-path="url(#burst-clip)" stroke="${ink}" stroke-width="1" fill="none">
${burstLines.join('\n')}
  </g>
  <rect x="${pad + 0.5}" y="${pad + 0.5}" width="${w - pad * 2 - 1}" height="${h - pad * 2 - 1}" fill="none" stroke="${ink}" stroke-width="1"/>
  <circle cx="${pad + 1 + burstCX}" cy="${pad + 1 + burstCY}" r="${sr}" fill="${dot}"/>
</svg>`,
    label
  };
}

function makeBannerSVG({ w, h, markLeft, markTop, markSize, markRays, markCore, inverted = false, label }) {
  const ink = inverted ? PAPER : INK;
  const bg = inverted ? INK : PAPER;
  const { lines, coreR } = sunburstElements({ w: markSize, h: markSize, rays: markRays, coreRatio: markCore, variant: 'lines', ink, cx: markSize / 2, cy: markSize / 2 });
  const cx = (markLeft + markSize / 2).toFixed(2);
  const cy = (markTop + markSize / 2).toFixed(2);
  const sr = (coreR).toFixed(2);
  return {
    svg: `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${w}" height="${h}">
  <rect width="${w}" height="${h}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx}" cy="${cy}" r="${sr}" fill="${ink}"/>
</svg>`,
    label
  };
}

function makeLockupSVG({ w, h, markW, markH, markRays, markCore, inverted = false, plateBurst = false, label }) {
  const ink = inverted ? PAPER : INK;
  const bg = inverted ? INK : PAPER;

  if (plateBurst) {
    // Plate-burst lockup: a PlateBurst inside the card
    const pad = Math.round(Math.min(markW, markH) * 0.1);
    const innerW = markW - pad * 2 - 2;
    const innerH = markH - pad * 2 - 2;
    const { lines: burstLines, coreR } = sunburstElements({ w: innerW, h: innerH, rays: markRays, coreRatio: markCore, variant: 'lines', cx: innerW / 2, cy: innerH / 2, ink });
    const burstCX = (innerW / 2).toFixed(2);
    const burstCY = (innerH / 2).toFixed(2);
    const sr = (coreR).toFixed(2);
    return {
      svg: `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${w}" height="${h}">
  <rect width="${w}" height="${h}" fill="${bg}"/>
  <g>
    <clipPath id="burst-clip">
      <rect x="${pad + 1}" y="${pad + 1}" width="${innerW}" height="${innerH}"/>
    </clipPath>
  </g>
  <g clip-path="url(#burst-clip)" stroke="${ink}" stroke-width="1" fill="none">
${burstLines.join('\n')}
  </g>
  <rect x="${pad + 0.5}" y="${pad + 0.5}" width="${markW - pad * 2 - 1}" height="${markH - pad * 2 - 1}" fill="none" stroke="${ink}" stroke-width="1"/>
  <circle cx="${pad + 1 + parseFloat(burstCX)}" cy="${pad + 1 + parseFloat(burstCY)}" r="${sr}" fill="${ink}"/>
</svg>`,
      label
    };
  }

  // Simple lockup: sunburst mark only (text is type, better done in Figma or as separate SVGs with text elements)
  const { lines, coreR } = sunburstElements({ w: markW, h: markH, rays: markRays, coreRatio: markCore, variant: 'lines', ink, cx: markW / 2, cy: markH / 2 });
  const cx = (markW / 2).toFixed(2);
  const cy = (markH / 2).toFixed(2);
  const sr = (coreR).toFixed(2);
  return {
    svg: `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${w}" height="${h}">
  <rect width="${w}" height="${h}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx}" cy="${cy}" r="${sr}" fill="${ink}"/>
</svg>`,
    label
  };
}

// ── All outputs ──────────────────────────────────────────────────────────
const outputs = [];

// 1. Density Sweep (lines, 240x240, coreRatio 0.20)
for (const rays of [36, 64, 96, 144, 192]) {
  outputs.push(makeSunburstSVG({
    w: 240, h: 240, rays, coreRatio: 0.20, variant: 'lines',
    label: `sunburst-${rays}-rays-240`
  }));
}

// 2. Taper Variants (300x300, coreRatio 0.18)
outputs.push(makeSunburstSVG({ w: 300, h: 300, rays: 96, coreRatio: 0.18, variant: 'lines', label: 'sunburst-hairlines-96' }));
outputs.push(makeSunburstSVG({ w: 300, h: 300, rays: 48, coreRatio: 0.18, variant: 'wedges', label: 'sunburst-wedges-48' }));
outputs.push(makeSunburstSVG({ w: 300, h: 300, rays: 96, coreRatio: 0.18, variant: 'tapered', label: 'sunburst-tapered-96' }));

// 3. Plate + Burst
outputs.push(makePlateBurstSVG({ w: 360, h: 360, rays: 96, coreRatio: 0.16, label: 'plate-burst-square' }));
outputs.push(makePlateBurstSVG({ w: 520, h: 260, rays: 120, coreRatio: 0.20, label: 'plate-burst-landscape' }));
outputs.push(makePlateBurstSVG({ w: 220, h: 360, rays: 80, coreRatio: 0.20, label: 'plate-burst-portrait' }));

// 4. Inverted
outputs.push(makeSunburstSVG({ w: 360, h: 360, rays: 96, coreRatio: 0.20, variant: 'lines', bg: INK, ink: PAPER, dot: PAPER, label: 'sunburst-inverted-96' }));
outputs.push(makeSunburstSVG({ w: 360, h: 360, rays: 120, coreRatio: 0.20, variant: 'lines', bg: INK, ink: PAPER, dot: '#a01818', label: 'sunburst-red-atom-120' }));
outputs.push(makeSunburstSVG({ w: 360, h: 360, rays: 48, coreRatio: 0.20, variant: 'wedges', bg: INK, ink: PAPER, dot: PAPER, label: 'sunburst-wedges-inverted-48' }));

// 5. Banners (mark-only extraction — full banners have text that should stay in Figma)
outputs.push(makeBannerSVG({
  w: 1280, h: 360, markLeft: -40, markTop: -40, markSize: 440, markRays: 144, markCore: 0.18, inverted: false,
  label: 'banner-hero-mark'
}));
outputs.push(makeBannerSVG({
  w: 1280, h: 360, markLeft: 840, markTop: -80, markSize: 520, markRays: 160, markCore: 0.16, inverted: true,
  label: 'banner-ink-dramatic-mark'
}));

// 6. Lockups (mark-only — standalone sunburst at lockup sizes)
outputs.push(makeLockupSVG({ w: 200, h: 200, markW: 200, markH: 200, markRays: 120, markCore: 0.18, label: 'lockup-stacked-mark' }));
outputs.push(makeLockupSVG({ w: 140, h: 140, markW: 140, markH: 140, markRays: 96, markCore: 0.18, label: 'lockup-horizontal-mark' }));
outputs.push(makeLockupSVG({ w: 220, h: 220, markW: 220, markH: 220, markRays: 96, markCore: 0.16, plateBurst: true, label: 'lockup-plate-burst-mark' }));
outputs.push(makeLockupSVG({ w: 200, h: 200, markW: 200, markH: 200, markRays: 120, markCore: 0.18, inverted: true, label: 'lockup-stacked-inverted-mark' }));
outputs.push(makeLockupSVG({ w: 140, h: 140, markW: 140, markH: 140, markRays: 96, markCore: 0.18, inverted: true, label: 'lockup-horizontal-inverted-mark' }));

// 7. Scale Test — Burst at Size
const scaleBurst = [
  { s: 256, rays: 144, core: 0.20 },
  { s: 160, rays: 144, core: 0.20 },
  { s: 96, rays: 96, core: 0.20 },
  { s: 64, rays: 60, core: 0.26 },
  { s: 48, rays: 40, core: 0.26 },
  { s: 32, rays: 28, core: 0.34 },
  { s: 24, rays: 20, core: 0.34 },
  { s: 16, rays: 16, core: 0.45 },
];
for (const { s, rays, core } of scaleBurst) {
  outputs.push(makeSunburstSVG({ w: s, h: s, rays, coreRatio: core, variant: 'lines', label: `sunburst-scale-${s}px` }));
}

// 8. Scale Test — Round (Avatar) — same geometries, just circular viewport
const scaleRound = [
  { s: 128, rays: 96, core: 0.22 },
  { s: 96, rays: 96, core: 0.22 },
  { s: 64, rays: 60, core: 0.28 },
  { s: 48, rays: 40, core: 0.28 },
  { s: 32, rays: 28, core: 0.36 },
  { s: 24, rays: 20, core: 0.36 },
  { s: 16, rays: 16, core: 0.48 },
];
for (const { s, rays, core } of scaleRound) {
  outputs.push(makeSunburstSVG({
    w: s, h: s, rays, coreRatio: core, variant: 'lines',
    label: `sunburst-round-${s}px`
  }));
}

// ── Write ────────────────────────────────────────────────────────────────
mkdirSync(OUT, { recursive: true });

for (const { svg, label } of outputs) {
  const path = join(OUT, `${label}.svg`);
  writeFileSync(path, svg, 'utf-8');
  console.log(`  ✓ ${label}.svg`);
}

console.log(`\n✨ Generated ${outputs.length} SVG files to ${OUT}`);

