#!/usr/bin/env node
/**
 * Generate standalone SVG files from the Sunburst Study React components.
 * v2 — includes full lockups and banners with SVG text elements.
 */

import { writeFileSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT = join(__dirname, 'assets', 'study-extracted');

const INK = '#0a0a0a';
const PAPER = '#f4f1ea';

// ── Geometry helpers ─────────────────────────────────────────────────────
function sunburstElements({ w, h, rays = 96, coreRatio = 0.18, variant = 'lines', cx, cy, ink = INK }) {
  cx = cx ?? w / 2;
  cy = cy ?? h / 2;
  const short = Math.min(w, h);
  const coreR = (short * coreRatio) / 2;
  const startR = coreR + 1;
  const outerR = Math.hypot(w, h) * 0.7;

  const lines = [];
  if (variant === 'lines') {
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      lines.push(`      <line x1="${(cx + Math.cos(a) * startR).toFixed(2)}" y1="${(cy + Math.sin(a) * startR).toFixed(2)}" x2="${(cx + Math.cos(a) * outerR).toFixed(2)}" y2="${(cy + Math.sin(a) * outerR).toFixed(2)}" stroke="${ink}" stroke-width="1"/>`);
    }
  } else if (variant === 'wedges') {
    const step = (Math.PI * 2) / rays;
    for (let i = 0; i < rays; i += 2) {
      const a0 = i * step, a1 = (i + 1) * step;
      lines.push(`      <path d="M ${(cx + Math.cos(a0) * startR).toFixed(2)} ${(cy + Math.sin(a0) * startR).toFixed(2)} L ${(cx + Math.cos(a1) * startR).toFixed(2)} ${(cy + Math.sin(a1) * startR).toFixed(2)} L ${(cx + Math.cos(a1) * outerR).toFixed(2)} ${(cy + Math.sin(a1) * outerR).toFixed(2)} L ${(cx + Math.cos(a0) * outerR).toFixed(2)} ${(cy + Math.sin(a0) * outerR).toFixed(2)} Z" fill="${ink}"/>`);
    }
  } else if (variant === 'tapered') {
    for (let i = 0; i < rays; i++) {
      const a = (i / rays) * Math.PI * 2;
      const sw = i % 4 === 0 ? '1.5' : '1';
      lines.push(`      <line x1="${(cx + Math.cos(a) * startR).toFixed(2)}" y1="${(cy + Math.sin(a) * startR).toFixed(2)}" x2="${(cx + Math.cos(a) * outerR).toFixed(2)}" y2="${(cy + Math.sin(a) * outerR).toFixed(2)}" stroke="${ink}" stroke-width="${sw}"/>`);
    }
  }
  return { lines, coreR };
}

function svgSunburst({ w, h, rays, coreRatio, variant, bg = 'transparent', ink = INK, dot = INK }) {
  const { lines, coreR } = sunburstElements({ w, h, rays, coreRatio, variant, ink });
  const cx = (w / 2).toFixed(2);
  const cy = (h / 2).toFixed(2);
  return `<rect width="${w}" height="${h}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx}" cy="${cy}" r="${(coreR).toFixed(2)}" fill="${dot}"/>`;
}

function svgPlateBurst({ w, h, rays = 96, variant = 'lines', coreRatio = 0.16, frameInset = 0.04, bg = PAPER, ink = INK, dot = INK }) {
  const pad = Math.round(Math.min(w, h) * frameInset);
  const innerW = w - pad * 2 - 2;
  const innerH = h - pad * 2 - 2;
  const { lines: burstLines, coreR } = sunburstElements({ w: innerW, h: innerH, rays, coreRatio, variant, cx: innerW / 2, cy: innerH / 2, ink });
  const burstCX = (innerW / 2).toFixed(2);
  const burstCY = (innerH / 2).toFixed(2);
  return `<rect width="${w}" height="${h}" fill="${bg}"/>
  <defs><clipPath id="cp"><rect x="${pad + 1}" y="${pad + 1}" width="${innerW}" height="${innerH}"/></clipPath></defs>
  <g clip-path="url(#cp)" stroke="${ink}" stroke-width="1" fill="none">
${burstLines.join('\n')}
  </g>
  <rect x="${pad + 0.5}" y="${pad + 0.5}" width="${w - pad * 2 - 1}" height="${h - pad * 2 - 1}" fill="none" stroke="${ink}" stroke-width="1"/>
  <circle cx="${pad + 1 + parseFloat(burstCX)}" cy="${pad + 1 + parseFloat(burstCY)}" r="${(coreR).toFixed(2)}" fill="${dot}"/>`;
}

function wrapSVG(content, w, h) {
  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${w}" height="${h}">
${content}
</svg>`;
}

// ── Builders ─────────────────────────────────────────────────────────────

function sunburst({ w, h, rays, coreRatio, variant, bg, ink, dot, label }) {
  return {
    svg: wrapSVG(svgSunburst({ w, h, rays, coreRatio, variant, bg, ink, dot }), w, h),
    label
  };
}

function plateburst({ w, h, rays, variant, coreRatio, bg, ink, dot, label }) {
  return {
    svg: wrapSVG(svgPlateBurst({ w, h, rays, variant, coreRatio, bg, ink, dot }), w, h),
    label
  };
}

function banner({ w, h, markLeft, markTop, markSize, markRays, markCore, inverted = false, label }) {
  const ink = inverted ? PAPER : INK;
  const bg = inverted ? INK : PAPER;
  const cx = markLeft + markSize / 2;
  const cy = markTop + markSize / 2;
  const { lines, coreR } = sunburstElements({ w: markSize, h: markSize, rays: markRays, coreRatio: markCore, variant: 'lines', cx, cy, ink });
  const body = `<rect width="${w}" height="${h}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx.toFixed(2)}" cy="${cy.toFixed(2)}" r="${(coreR).toFixed(2)}" fill="${ink}"/>`;
  return { svg: wrapSVG(body, w, h), label };
}

function lockup({ w, h, markW, markH, markRays, markCore, inverted = false, plateBurst = false, label }) {
  const ink = inverted ? PAPER : INK;
  const bg = inverted ? INK : PAPER;
  let body;
  if (plateBurst) {
    const pad = Math.round(Math.min(markW, markH) * 0.1);
    const innerW = markW - pad * 2 - 2;
    const innerH = markH - pad * 2 - 2;
    const { lines: burstLines, coreR } = sunburstElements({ w: innerW, h: innerH, rays: markRays, coreRatio: markCore, variant: 'lines', cx: innerW / 2, cy: innerH / 2, ink });
    const burstCX = innerW / 2;
    const burstCY = innerH / 2;
    body = `<rect width="${w}" height="${h}" fill="${bg}"/>
  <defs><clipPath id="cp"><rect x="${pad + 1}" y="${pad + 1}" width="${innerW}" height="${innerH}"/></clipPath></defs>
  <g clip-path="url(#cp)" stroke="${ink}" stroke-width="1" fill="none">
${burstLines.join('\n')}
  </g>
  <rect x="${pad + 0.5}" y="${pad + 0.5}" width="${markW - pad * 2 - 1}" height="${markH - pad * 2 - 1}" fill="none" stroke="${ink}" stroke-width="1"/>
  <circle cx="${(pad + 1 + burstCX).toFixed(2)}" cy="${(pad + 1 + burstCY).toFixed(2)}" r="${(coreR).toFixed(2)}" fill="${ink}"/>`;
  } else {
    const cx = markW / 2;
    const cy = markH / 2;
    const { lines, coreR } = sunburstElements({ w: markW, h: markH, rays: markRays, coreRatio: markCore, variant: 'lines', cx, cy, ink });
    body = `<rect width="${w}" height="${h}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx.toFixed(2)}" cy="${cy.toFixed(2)}" r="${(coreR).toFixed(2)}" fill="${ink}"/>`;
  }
  return { svg: wrapSVG(body, w, h), label };
}

// ── Full lockups with wordmark ───────────────────────────────────────────
function lockupFull({ cardW, cardH, markW, markH, markRays, markCore, inverted = false, plateBurst = false, stacked = true, label }) {
  const ink = inverted ? PAPER : INK;
  const bg = inverted ? INK : PAPER;
  const cx = markW / 2;
  const cy = markH / 2;
  const { lines, coreR } = sunburstElements({ w: markW, h: markH, rays: markRays, coreRatio: markCore, variant: 'lines', cx, cy, ink });

  const markSVG = plateBurst
    ? svgPlateBurst({ w: markW, h: markH, rays: markRays, coreRatio: markCore, bg, ink, dot: ink, frameInset: 0.1 })
    : `<g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx.toFixed(2)}" cy="${cy.toFixed(2)}" r="${(coreR).toFixed(2)}" fill="${ink}"/>`;

  const topTitleSize = Math.round(markRays >= 120 ? 30 : 38);
  const topSubSize = Math.round(markRays >= 120 ? 11 : 12);

  let body;
  if (stacked) {
    const gap = 22;
    const titleY = markH + gap + topTitleSize * 0.85;
    const subY = titleY + topSubSize + gap * 0.4;
    body = `<rect width="${cardW}" height="${cardH}" fill="${bg}"/>
${markSVG}
    <text x="${cardW / 2}" y="${titleY}" text-anchor="middle" font-family="'Archivo Black','Helvetica Neue',sans-serif" font-size="${topTitleSize}" letter-spacing="-0.01em" fill="${ink}">BLACK ATOM</text>
    <text x="${cardW / 2}" y="${subY}" text-anchor="middle" font-family="'JetBrains Mono',ui-monospace,monospace" font-size="${topSubSize}" letter-spacing="0.55em" fill="${ink}">INDUSTRIES</text>`;
  } else {
    const gap = 28;
    const titleSize = 38;
    const subSize = 12;
    const titleY = cardH / 2 - 10;
    const subY = titleY + titleSize + 10;
    body = `<rect width="${cardW}" height="${cardH}" fill="${bg}"/>
    <g transform="translate(${markW / 2}, ${cardH / 2})">${markSVG.replace('<rect', '<rect x="' + (-markW/2) + '" y="' + (-markH/2) + '"').replace(/^\s{2}/gm, '      ')}</g>
    <text x="${markW + gap}" y="${titleY}" font-family="'Archivo Black','Helvetica Neue',sans-serif" font-size="${titleSize}" letter-spacing="-0.01em" fill="${ink}">BLACK ATOM</text>
    <text x="${markW + gap}" y="${subY}" font-family="'JetBrains Mono',ui-monospace,monospace" font-size="${subSize}" letter-spacing="0.55em" fill="${ink}">INDUSTRIES</text>`;
  }
  return { svg: wrapSVG(body, cardW, cardH), label };
}

function bannerFull({ w, h, markLeft, markTop, markSize, markRays, markCore, inverted = false, label }) {
  const ink = inverted ? PAPER : INK;
  const bg = inverted ? INK : PAPER;
  const cx = markLeft + markSize / 2;
  const cy = markTop + markSize / 2;
  const { lines, coreR } = sunburstElements({ w: markSize, h: markSize, rays: markRays, coreRatio: markCore, variant: 'lines', cx, cy, ink });

  const textX = inverted ? 80 : 460;
  const subtitleY = inverted ? 108 : 90;
  const titleY = inverted ? subtitleY + 18 + 92 : subtitleY + 18 + 96;
  const industriesY = inverted ? titleY + 92 + 18 : titleY + 96 + 18;

  const body = `<rect width="${w}" height="${h}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${cx.toFixed(2)}" cy="${cy.toFixed(2)}" r="${(coreR).toFixed(2)}" fill="${ink}"/>
  <text x="${textX}" y="${subtitleY}" font-family="'JetBrains Mono',ui-monospace,monospace" font-size="11" letter-spacing="0.3em" fill="${ink}" opacity="0.7">${inverted ? 'SECTION 04 · RADIATION RECORD' : 'EST · MMXXVI · MATERIAL SCIENCES'}</text>
  <text x="${textX}" y="${titleY}" font-family="'Archivo Black','Helvetica Neue',sans-serif" font-size="${inverted ? 92 : 96}" letter-spacing="-0.02em" fill="${ink}">BLACK ATOM</text>
  <text x="${textX}" y="${industriesY}" font-family="'JetBrains Mono',ui-monospace,monospace" font-size="16" letter-spacing="0.55em" fill="${ink}">INDUSTRIES</text>`;
  return { svg: wrapSVG(body, w, h), label };
}

// ── Generate all ─────────────────────────────────────────────────────────
const outputs = [];

// 1. Density Sweep
for (const rays of [36, 64, 96, 144, 192]) {
  outputs.push(sunburst({ w: 240, h: 240, rays, coreRatio: 0.20, variant: 'lines', label: `sunburst-${rays}-rays-240` }));
}

// 2. Taper Variants
outputs.push(sunburst({ w: 300, h: 300, rays: 96, coreRatio: 0.18, variant: 'lines', label: 'sunburst-hairlines-96' }));
outputs.push(sunburst({ w: 300, h: 300, rays: 48, coreRatio: 0.18, variant: 'wedges', label: 'sunburst-wedges-48' }));
outputs.push(sunburst({ w: 300, h: 300, rays: 96, coreRatio: 0.18, variant: 'tapered', label: 'sunburst-tapered-96' }));

// 3. Plate + Burst
outputs.push(plateburst({ w: 360, h: 360, rays: 96, coreRatio: 0.16, label: 'plate-burst-square' }));
outputs.push(plateburst({ w: 520, h: 260, rays: 120, coreRatio: 0.20, label: 'plate-burst-landscape' }));
outputs.push(plateburst({ w: 220, h: 360, rays: 80, coreRatio: 0.20, label: 'plate-burst-portrait' }));

// 4. Inverted
outputs.push(sunburst({ w: 360, h: 360, rays: 96, coreRatio: 0.20, variant: 'lines', bg: INK, ink: PAPER, dot: PAPER, label: 'sunburst-inverted-96' }));
outputs.push(sunburst({ w: 360, h: 360, rays: 120, coreRatio: 0.20, variant: 'lines', bg: INK, ink: PAPER, dot: '#a01818', label: 'sunburst-red-atom-120' }));
outputs.push(sunburst({ w: 360, h: 360, rays: 48, coreRatio: 0.20, variant: 'wedges', bg: INK, ink: PAPER, dot: PAPER, label: 'sunburst-wedges-inverted-48' }));

// 5. Banners (mark only + full with text)
outputs.push(banner({ w: 1280, h: 360, markLeft: -40, markTop: -40, markSize: 440, markRays: 144, markCore: 0.18, label: 'banner-hero-mark' }));
outputs.push(banner({ w: 1280, h: 360, markLeft: 840, markTop: -80, markSize: 520, markRays: 160, markCore: 0.16, inverted: true, label: 'banner-ink-dramatic-mark' }));
outputs.push(bannerFull({ w: 1280, h: 360, markLeft: -40, markTop: -40, markSize: 440, markRays: 144, markCore: 0.18, label: 'banner-hero-full' }));
outputs.push(bannerFull({ w: 1280, h: 360, markLeft: 840, markTop: -80, markSize: 520, markRays: 160, markCore: 0.16, inverted: true, label: 'banner-ink-dramatic-full' }));

// 6. Lockups (mark only + full with text)
outputs.push(lockup({ w: 200, h: 200, markW: 200, markH: 200, markRays: 120, markCore: 0.18, label: 'lockup-stacked-mark' }));
outputs.push(lockup({ w: 140, h: 140, markW: 140, markH: 140, markRays: 96, markCore: 0.18, label: 'lockup-horizontal-mark' }));
outputs.push(lockup({ w: 220, h: 220, markW: 220, markH: 220, markRays: 96, markCore: 0.16, plateBurst: true, label: 'lockup-plate-burst-mark' }));
outputs.push(lockup({ w: 200, h: 200, markW: 200, markH: 200, markRays: 120, markCore: 0.18, inverted: true, label: 'lockup-stacked-inverted-mark' }));
outputs.push(lockup({ w: 140, h: 140, markW: 140, markH: 140, markRays: 96, markCore: 0.18, inverted: true, label: 'lockup-horizontal-inverted-mark' }));

outputs.push(lockupFull({ cardW: 360, cardH: 308, markW: 200, markH: 200, markRays: 120, markCore: 0.18, stacked: true, label: 'lockup-stacked-full' }));
outputs.push(lockupFull({ cardW: 520, cardH: 212, markW: 140, markH: 140, markRays: 96, markCore: 0.18, stacked: false, label: 'lockup-horizontal-full' }));
outputs.push(lockupFull({ cardW: 360, cardH: 304, markW: 220, markH: 220, markRays: 96, markCore: 0.16, plateBurst: true, stacked: true, label: 'lockup-plate-burst-full' }));
outputs.push(lockupFull({ cardW: 360, cardH: 308, markW: 200, markH: 200, markRays: 120, markCore: 0.18, stacked: true, inverted: true, label: 'lockup-stacked-inverted-full' }));
outputs.push(lockupFull({ cardW: 520, cardH: 212, markW: 140, markH: 140, markRays: 96, markCore: 0.18, stacked: false, inverted: true, label: 'lockup-horizontal-inverted-full' }));

// 7. Scale Test — Burst at Size
for (const { s, rays, core } of [
  { s: 256, rays: 144, core: 0.20 }, { s: 160, rays: 144, core: 0.20 },
  { s: 96, rays: 96, core: 0.20 },  { s: 64, rays: 60, core: 0.26 },
  { s: 48, rays: 40, core: 0.26 },  { s: 32, rays: 28, core: 0.34 },
  { s: 24, rays: 20, core: 0.34 },  { s: 16, rays: 16, core: 0.45 },
]) {
  outputs.push(sunburst({ w: s, h: s, rays, coreRatio: core, variant: 'lines', label: `sunburst-scale-${s}px` }));
}

// 8. Scale Test — Round
for (const { s, rays, core } of [
  { s: 128, rays: 96, core: 0.22 }, { s: 96, rays: 96, core: 0.22 },
  { s: 64, rays: 60, core: 0.28 },  { s: 48, rays: 40, core: 0.28 },
  { s: 32, rays: 28, core: 0.36 },  { s: 24, rays: 20, core: 0.36 },
  { s: 16, rays: 16, core: 0.48 },
]) {
  outputs.push(sunburst({ w: s, h: s, rays, coreRatio: core, variant: 'lines', label: `sunburst-round-${s}px` }));
}

// ── Write ────────────────────────────────────────────────────────────────
mkdirSync(OUT, { recursive: true });
for (const { svg, label } of outputs) {
  writeFileSync(join(OUT, `${label}.svg`), svg, 'utf-8');
  console.log(`  ✓ ${label}.svg`);
}

console.log(`\n✨ Generated ${outputs.length} SVG files to ${OUT}`);

