    <text x="${cardW / 2}" y="${subY}" text-anchor="middle" font-family="'JetBrains Mono',ui-monospace,monospace" font-size="${topSubSize}" letter-spacing="0.55em" fill="${ink}">INDUSTRIES</text>`;
    } else {
      const { lines, coreR } = sunburstElements({ w: markW, h: markH, rays: markRays, coreRatio: markCore, variant: 'lines', cx: markCX, cy: markCY, ink });
      body = `<rect width="${cardW}" height="${cardH}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${markCX.toFixed(2)}" cy="${markCY.toFixed(2)}" r="${(coreR).toFixed(2)}" fill="${ink}"/>
    <text x="${cardW / 2}" y="${titleY}" text-anchor="middle" font-family="'Archivo Black','Helvetica Neue',sans-serif" font-size="${topTitleSize}" letter-spacing="-0.01em" fill="${ink}">BLACK ATOM</text>
    <text x="${cardW / 2}" y="${subY}" text-anchor="middle" font-family="'JetBrains Mono',ui-monospace,monospace" font-size="${topSubSize}" letter-spacing="0.55em" fill="${ink}">INDUSTRIES</text>`;
    }
  } else {
    // Mark left, text right — mark vertically centered
    const gap = 28;
    const titleSize = 38;
    const subSize = 12;
    const markTop = (cardH - markH) / 2;
    const markCXAbs = markW / 2;
    const markCYAbs = markTop + markH / 2;
    const titleY = cardH / 2 - 2;
    const subY = titleY + titleSize + 8;
    const { lines, coreR } = sunburstElements({ w: markW, h: markH, rays: markRays, coreRatio: markCore, variant: 'lines', cx: markCXAbs, cy: markCYAbs, ink });
    body = `<rect width="${cardW}" height="${cardH}" fill="${bg}"/>
  <g stroke="${ink}" stroke-width="1" fill="none">
${lines.join('\n')}
  </g>
  <circle cx="${markCXAbs.toFixed(2)}" cy="${markCYAbs.toFixed(2)}" r="${(coreR).toFixed(2)}" fill="${ink}"/>
    <text x="${markW + gap}" y="${titleY}" font-family="'Archivo Black','Helvetica Neue',sans-serif" font-size="${titleSize}" letter-spacing="-0.01em" fill="${ink}">BLACK ATOM</text>
    <text x="${markW + gap}" y="${subY}" font-family="'JetBrains Mono',ui-monospace,monospace" font-size="${subSize}" letter-spacing="0.55em" fill="${ink}">INDUSTRIES</text>`;
  }
  return { svg: wrapSVG(body, cardW, cardH), label };
}

